/* ── Dark, clean theme ── */

/* System font stack, reset body */
body {
  margin: 0;
  font-family:
    -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Fira Sans',
    'Droid Sans', 'Helvetica Neue', Arial, sans-serif;
  font-size: 14px;
  color: #e6e6e6;
  background: #1e1e1e;
}

/* Subtle accent link – used sparingly */
a {
  color: #6aa6ff;
  text-decoration: none;
}
a:hover {
  text-decoration: underline;
}

/* ── Page layout ──
   The app fills the viewport as a column so the embedded host (and therefore
   the scrollable results) gets a definite height in both views. */
html,
body {
  height: 100%;
}
#app {
  height: 100vh;
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 12px;
  box-sizing: border-box;
}

/* ── File-browser widget + hosts ──
   The widget is CHROMELESS: no border, background, or title of its own. It is
   a flex column that fills whichever host renders it (the embedded host or the
   dialog body), keeping the results area scrollable in both contexts. */
.file-browser {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}
/* Embedded host: the primary, chromeless surface while the dialog is closed. */
.file-browser-host {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}
/* Dialog body slot: the widget is moved here on open. Flexes to fill the
   dialog's remaining height below the titlebar. */
.browser-dialog .dialog-body {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}

/* ── Trigger button (toggle file browser) ── */
.trigger {
  padding: 8px 16px;
  cursor: pointer;
  background: #3a3d41;
  border: none;
  color: inherit;
  border-radius: 4px;
  font-size: 14px;
}
.trigger:hover {
  background: #45494d;
}

/* ── Native <dialog> styling ── */
/* Base chrome only (background/border/size/padding). Crucially we do NOT set
   `display` here: a closed <dialog> is hidden by the UA rule
   `dialog:not([open]) { display: none }`, but any author `display` declaration
   overrides the UA sheet entirely and would keep the closed dialog (and thus
   its frame/titlebar) visible on the page. The flex column layout is applied
   ONLY to the open dialog below. */
.browser-dialog {
  background: #252526;
  color: #e6e6e6;
  border: 1px solid #3c3c3c;
  border-radius: 8px;
  /* Fixed size, clamped so it never overflows small viewports. */
  width: 960px;
  max-width: 94vw;
  height: 640px;
  max-height: 90vh;
  padding: 16px;
  /* Remove default UA margin/padding */
  margin: auto;
  box-sizing: border-box;
}
/* Flex column layout only while open, so the closed dialog stays
   `display: none` (hidden) and renders its frame only when shown. */
.browser-dialog[open] {
  display: flex;
  flex-direction: column;
}
.browser-dialog::backdrop {
  background: rgba(0, 0, 0, 0.6);
}

/* ── Header row ── */
.dialog-header {
  position: relative;
  display: flex;
  justify-content: flex-end;
  align-items: center;
  margin-bottom: 12px;
}
/* Title is absolutely centered across the full dialog width so the close
   button's width never offsets it. pointer-events:none keeps the centered
   text from intercepting clicks meant for the button. */
.dialog-header .title {
  position: absolute;
  left: 0;
  right: 0;
  text-align: center;
  margin: 0;
  font-size: 16px;
  font-weight: 600;
  pointer-events: none;
}
.dialog-header .close-btn {
  position: relative;
  z-index: 1;
  background: none;
  border: none;
  color: #9a9a9a;
  cursor: pointer;
  font-size: 20px;
  line-height: 1;
  padding: 4px 8px;
  border-radius: 4px;
}
.dialog-header .close-btn:hover {
  color: #e6e6e6;
  background: #2d2d30;
}

/* ── Toolbar ── */
.toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
  margin-bottom: 12px;
}

/* Breadcrumb */
.breadcrumb {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-wrap: wrap;
}
.breadcrumb a {
  color: #9a9a9a;
  font-size: 13px;
}
.breadcrumb a:hover {
  color: #e6e6e6;
  text-decoration: none;
}

/* Search input */
.toolbar input[type='search'],
.toolbar input[type='text'] {
  background: #333337;
  color: #e6e6e6;
  border: 1px solid #3c3c3c;
  border-radius: 4px;
  padding: 6px 10px;
  font-size: 13px;
  outline: none;
  box-sizing: border-box;
  margin-left: auto;
}
.toolbar input[type='search']::placeholder,
.toolbar input[type='text']::placeholder {
  color: #9a9a9a;
}
.toolbar input[type='search']:focus,
.toolbar input[type='text']:focus {
  border-color: #6aa6ff;
}

/* ── Search wrapper, in-input icons, visibility toggling ──
   The search input is wrapped in .search-wrapper so a search glyph and a
   clear button can be overlaid inside the right edge of the input. The
   wrapper becomes the toolbar's right-aligned flex child (margin-left: auto),
   replacing the margin-left:auto that was on the bare input. */

/* ── Search wrapper, in-input icons, visibility toggling ──
   The search input is wrapped in .search-wrapper so a search glyph and a
   clear button can be overlaid inside the right edge of the input. The
   wrapper becomes the toolbar's right-aligned flex child (margin-left: auto),
   replacing the margin-left:auto that was on the bare input. */
.search-wrapper {
  position: relative;
  display: inline-flex;
  align-items: center;
  margin-left: auto;
}
/* Override the inherited .toolbar input margin-left:auto (the wrapper handles
   positioning now) and reserve space so typed text never slides under the
   absolutely-positioned icon. */
.search-wrapper input[type='text'] {
  margin-left: 0;
  padding-right: 28px;
}
/* Both overlays sit inside the input's right edge. The search icon is
   decorative (no clicks); the clear button must stay clickable. */
.search-wrapper .search-icon,
.search-wrapper .clear-btn {
  position: absolute;
  right: 6px;
  color: #9a9a9a;
}
.search-wrapper .search-icon {
  pointer-events: none;
}
.search-wrapper .clear-btn {
  background: none;
  border: none;
  cursor: pointer;
  padding: 2px;
  display: inline-flex;
  align-items: center;
  line-height: 1;
}
.search-wrapper .clear-btn:hover {
  color: #e6e6e6;
}
/* Visibility toggling via :placeholder-shown (no JS). The icon and button are
   siblings AFTER the input, so the general sibling combinator ~ applies.
   Empty input (placeholder shown): search icon visible, clear button hidden. */
.search-wrapper .clear-btn {
  display: none;
}
/* Input has text (placeholder NOT shown): swap — hide search icon, show clear. */
.search-wrapper input:not(:placeholder-shown) ~ .search-icon {
  display: none;
}
.search-wrapper input:not(:placeholder-shown) ~ .clear-btn {
  display: inline-flex;
}

/* ── Results container (scrollable) ──
   Grows to fill its host's remaining height (flex: 1) and scrolls when the
   table body overflows. `min-height: 0` lets the flex item shrink below its
   content so the scrollbar engages. The table header is made sticky below, so
   only the body rows scroll.

   `padding-bottom: var(--browse-row-height)` reserves one row-height of blank
   space at the bottom of the scroll region. This guarantees there is ALWAYS a
   clickable blank area below the last row — even when the table is full and
   scrolled — so a right-click there can open the current-directory context
   menu (see setupDirContextMenu in dom-builders.ts). A `<tr>` margin cannot
   do this: table rows ignore `margin` entirely under `border-collapse`, so
   the space is provided as container padding instead. The blank area is the
   `.results` element itself (not within the `table`), which is exactly what
   the contextmenu listener keys on to distinguish blank space from rows. */
.results {
  flex: 1;
  min-height: 0;
  overflow: auto;
  border: 1px solid #3c3c3c;
  border-radius: 4px;
  /* One data-row's height (33px = 14px font line-box + 6px*2 td padding,
   * measured against the app font stack). Keep in sync with the row metrics. */
  --browse-row-height: 33px;
  padding-bottom: var(--browse-row-height);
}

/* ── Table ── */
.results-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: auto;
}
.results-table th,
.results-table td {
  padding: 6px 8px;
  text-align: left;
  white-space: nowrap;
}
.results-table th {
  color: #9a9a9a;
  font-weight: 500;
  position: sticky;
  top: 0;
  background: #252526;
  z-index: 1;
  border-bottom: 1px solid #3c3c3c;
}
.results-table tbody tr:hover {
  background: #2d2d30;
}

/* ── Small action buttons ── */
.btn {
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  cursor: pointer;
  background: #3a3d41;
  border: none;
  color: inherit;
  border-radius: 4px;
  font-size: 12px;
  line-height: 1.4;
  white-space: nowrap;
}
.btn:hover {
  background: #45494d;
}
.btn:disabled {
  opacity: 0.5;
  cursor: default;
}
.btn:disabled:hover {
  background: #3a3d41;
}

